import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as s,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Додавання каналу Yandex","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/yandex.md","filePath":"uk-UA/upload/yandex.md","lastUpdated":1781962217000}'),l={name:"uk-UA/upload/yandex.md"};function c(p,e,h,x,m,b){return s(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="додавання-каналу-yandex" tabindex="-1">Додавання каналу Yandex <a class="header-anchor" href="#додавання-каналу-yandex" aria-label="Permalink to &quot;Додавання каналу Yandex&quot;">​</a></h1><h2 id="що-підготувати-спочатку" tabindex="-1">Що підготувати спочатку <a class="header-anchor" href="#що-підготувати-спочатку" aria-label="Permalink to &quot;Що підготувати спочатку&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>Обліковий запис Yandex</td><td>Для входу й авторизації Yandex Disk</td></tr><tr><td>Yandex OAuth app</td><td>Для отримання <code>Client ID</code> і <code>Client Secret</code></td></tr><tr><td>Ваш домен ImgBed</td><td>Для OAuth redirect URI</td></tr><tr><td>Доступне сховище Yandex Disk</td><td>Фактичне місце зберігання файлів</td></tr></tbody></table><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><h3 id="крок-1-створіть-yandex-oauth-app" tabindex="-1">Крок 1. Створіть Yandex OAuth app <a class="header-anchor" href="#крок-1-створіть-yandex-oauth-app" aria-label="Permalink to &quot;Крок 1. Створіть Yandex OAuth app&quot;">​</a></h3><ol><li>Відкрийте сторінку створення Yandex OAuth app:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>Якщо вас перенаправить на вхід, спочатку увійдіть у свій Yandex-акаунт.</li><li>Створіть новий app.</li><li>Дайте app зрозумілу назву, наприклад <code>imgbed-yandex</code>.</li><li>Знайдіть налаштування callback або redirect URL.</li><li>Введіть:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="крок-2-перевірте-permissions" tabindex="-1">Крок 2. Перевірте permissions <a class="header-anchor" href="#крок-2-перевірте-permissions" aria-label="Permalink to &quot;Крок 2. Перевірте permissions&quot;">​</a></h3><p>Для поточної інтеграції ImgBed з Yandex залиште ці чотири permissions у <code>Yandex.Disk REST API</code>:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Призначення</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>Дозволяє ImgBed зберігати файли в app folder</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Читає файли й посилання для завантаження</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Завантажує файли, створює папки й видаляє файли</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Читає квоту диска й використаний обсяг</td></tr></tbody></table><p>Якщо ви також бачите такі permissions у <code>Yandex ID API</code>, вони необов&#39;язкові:</p><table tabindex="0"><thead><tr><th>Текст permission</th><th>Рекомендація</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Необов&#39;язково</td></tr><tr><td><code>Access to email address</code></td><td>Необов&#39;язково</td></tr></tbody></table><p>Основні можливості завантаження, скачування, видалення й квот переважно залежать від чотирьох permissions <code>Yandex.Disk REST API</code>, наведених вище.</p><p><img src="'+t+'" alt="Налаштування permissions Yandex Disk" loading="lazy"></p><h3 id="крок-3-скопіюите-credentials-app" tabindex="-1">Крок 3. Скопіюйте credentials app <a class="header-anchor" href="#крок-3-скопіюите-credentials-app" aria-label="Permalink to &quot;Крок 3. Скопіюйте credentials app&quot;">​</a></h3><p>Після створення app скопіюйте:</p><table tabindex="0"><thead><tr><th>Поле Yandex</th><th>Поле ImgBed</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Запис Client ID і Secret" loading="lazy"></p><h3 id="крок-4-заповніть-канал-yandex" tabindex="-1">Крок 4. Заповніть канал Yandex <a class="header-anchor" href="#крок-4-заповніть-канал-yandex" aria-label="Permalink to &quot;Крок 4. Заповніть канал Yandex&quot;">​</a></h3><p>У налаштуваннях завантаження виберіть <code>Yandex</code> і заповніть:</p><table tabindex="0"><thead><tr><th>Поле ImgBed</th><th>Що ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Зрозуміла назва, наприклад <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td><code>Client ID</code> Yandex app</td></tr><tr><td>Client Secret</td><td><code>Client Secret</code> Yandex app</td></tr><tr><td>Refresh Token</td><td>Поки залиште порожнім</td></tr><tr><td>Root directory</td><td>Необов&#39;язково. Типово <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+d+'" alt="Редагування конфігурації каналу" loading="lazy"></p><h3 id="крок-5-отримаите-refresh-token" tabindex="-1">Крок 5. Отримайте Refresh Token <a class="header-anchor" href="#крок-5-отримаите-refresh-token" aria-label="Permalink to &quot;Крок 5. Отримайте Refresh Token&quot;">​</a></h3><ol><li>В ImgBed натисніть <code>Get Token</code>.</li><li>Увійдіть у Yandex-акаунт, який хочете підключити.</li><li>Підтвердьте запит авторизації.</li><li>На callback-сторінці з&#39;явиться <code>Refresh Token</code>.</li><li>Скопіюйте його.</li><li>Поверніться до ImgBed і вставте його в поле <code>Refresh Token</code>.</li></ol><p><img src="'+n+`" alt="Копіювання refresh token після авторизації" loading="lazy"></p><h3 id="крок-6-збережіть-канал" tabindex="-1">Крок 6. Збережіть канал <a class="header-anchor" href="#крок-6-збережіть-канал" aria-label="Permalink to &quot;Крок 6. Збережіть канал&quot;">​</a></h3><p>Коли всі поля заповнені, збережіть канал.</p><h2 id="короткии-сценаріи" tabindex="-1">Короткий сценарій <a class="header-anchor" href="#короткии-сценаріи" aria-label="Permalink to &quot;Короткий сценарій&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Відкрити Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Створити app</span></span>
<span class="line"><span>-&gt; Додати https://your-domain.com/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Перевірити permissions Yandex Disk</span></span>
<span class="line"><span>-&gt; Скопіювати Client ID і Client Secret</span></span>
<span class="line"><span>-&gt; Ввести Client ID / Client Secret в ImgBed</span></span>
<span class="line"><span>-&gt; Натиснути Get Token</span></span>
<span class="line"><span>-&gt; Скопіювати Refresh Token з callback-сторінки</span></span>
<span class="line"><span>-&gt; Вставити його назад в ImgBed і зберегти</span></span></code></pre></div><h2 id="посилання" tabindex="-1">Посилання <a class="header-anchor" href="#посилання" aria-label="Permalink to &quot;Посилання&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const y=o(l,[["render",c]]);export{g as __pageData,y as default};
